// DETERMINISTIC clean-sheet teardown (mirrors services/costing.py).
// 5-element build-up: material -> +overhead -> +SG&A -> +margin = should-cost floor/target.
const d = $json;
const c2 = (x) => Math.round(x * 100) / 100;

// 1. Direct material per component.
let material = 0;
for (const ln of d.bom) {
  if (ln.method === 'teardown')      material += ln.base_cost * ln.commodity_index;
  else if (ln.method === 'reference_price') material += ln.list_price * (1 - ln.discount_band);
}

// 2-5. Build up to floor + target.
const works_cost = material * (1 + d.overhead_pct);     // + manufacturing overhead
const should_cost_floor = works_cost * (1 + d.sga_pct); // + SG&A  (our cost floor)
const target_price = should_cost_floor * (1 + d.margin_pct); // + fair margin (target)

// Gaps vs the vendor quote.
const gap_to_target = d.vendor_quote - target_price;
const gap_to_floor  = d.vendor_quote - should_cost_floor;
const gap_pct = target_price > 0 ? (gap_to_target / target_price) : 0;

return [{ json: {
  product: d.product,
  vendor_quote: d.vendor_quote,
  material: c2(material),
  should_cost_floor: c2(should_cost_floor),
  target_price: c2(target_price),
  gap_to_target: c2(gap_to_target),     // the addressable negotiation saving
  gap_to_floor: c2(gap_to_floor),
  gap_pct: Math.round(gap_pct * 1000) / 10,
  verdict: gap_to_target > 0 ? 'quote ABOVE fair target — negotiate' : 'quote at/below target — fair'
}}];

